import React, { useState } from 'react';
import { View, Text, Button, TouchableWithoutFeedback, ActivityIndicator } from 'react-native';
import { Biometry, BiometricAuthenticationError } from 'react-native-biometrics';

const AuthScreen = () => {
  const [authenticating, setAuthenticating] = useState(false);
  const [fallback, setFallback] = useState(false);

  const storeData = async (key, value) => {
    try {
      await AsyncStorage.setItem(key, value);
    } catch (error) {
      console.log('AsyncStorage error: ' + error.message);
    }
  };

  const handleBiometrics = async () => {
    setAuthenticating(true);

    if (!fallback) {
      try {
        const biometryType = await Biometry.isEnrolled();
        const authorized = await Biometry.authenticate({
          promptMessage: 'Scan your face or fingerprint to continue',
        });

        if (authorized) {
          storeData('authenticated', true);
        }
      } catch (error) {
        console.log(error.message);

        if (error instanceof BiometricAuthenticationError && error.code === BiometricAuthenticationError.ERROR_USER_CANCELLED) {
          setFallback(true);
        }

        setAuthenticating(false);
      }
    } else {
      try {
        const authorized = await Biometry.authenticate({
          promptMessage: 'Enter your password to continue',
        });

        if (authorized) {
          storeData('authenticated', true);
        }
      } catch (error) {
        console.log(error.message);

        setAuthenticating(false);
      }
    }

    setAuthenticating(false);
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      {authenticating ? (
        <ActivityIndicator size="large" color="#0000ff" />
      ) : fallback || AsyncStorage.getItem('authenticated') === true ? (
        <Text>You are already logged in!</Text>
      ) : (
        <View>
          <TouchableWithoutFeedback onPress={handleBiometrics}>
            <Text>Scan your face or fingerprint</Text>
          </TouchableWithoutFeedback>

          {fallback && (
            <TouchableWithoutFeedback onPress={handleBiometrics}>
              <Text>Enter your password instead</Text>
            </TouchableWithoutFeedback>
          )}
        </View>
      )}
    </View>
  );
};

export default AuthScreen;